							img.alt = textHide;
						} else {
							textSpan.textContent = textShow;
							img.src = iconShow;
							img.alt = textShow;
						}
					}

});
			}

// Aggiungi l'evento click per tutti i toggle di visibilità dei contenuti inclusi
			document.querySelectorAll('.ifq-paywall__included-toggle').forEach(toggleButton => {
